export class TreeNode {
  val: number;
  left: TreeNode | null;
  right: TreeNode | null;
  constructor(v: number) {
    this.val = v;
    this.left = null;
    this.right = null;
  }
}

/** \u5C42\u5E8F\uFF0C\u8FD4\u56DE\u6BCF\u5C42\u4E00\u5C42\u6570\u7EC4 */
export function levelOrder(root: TreeNode | null): number[][] {
  if (!root) {
    return [];
  }
  const res: number[][] = [];
  const q: TreeNode[] = [root];
  let f = 0;
  while (f < q.length) {
    const size = q.length - f;
    const row: number[] = [];
    for (let i = 0; i < size; i += 1) {
      const x = q[f]!;
      f += 1;
      row.push(x.val);
      if (x.left) {
        q.push(x.left);
      }
      if (x.right) {
        q.push(x.right);
      }
    }
    res.push(row);
  }
  return res;
}
